    }
  ],
  "proposed_actions": [
    {
      "action": "isolate_instance_sg",
      "target": "i-0f1e2d3c4b5a69788 (web-03) via sg-0aa11bb22cc33dd44 (web-tier-ssh), eu-west-2a",
      "justification": "203.0.113.42 scored 97/100 malicious reputation with 1,243 abuse reports (90d), tagged ssh-bruteforce/botnet/scanner. It made 41 TCP/22 attempts over 3.5 hrs. Isolating the SG removes the open-internet SSH exposure driving this attack without affecting application availability.",
      "risk_if_wrong": "Engineers may lose SSH access to web-03 if authorised management CIDRs are not allowlisted in the replacement SG first. Confirm SSH source ranges before applying.",
      "requires_approval": true,
      "status": "pending_approval"
    }
  ],
  "escalate_to_human": false
}
```

